  ('social-worker-moex-02788', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會保險未來的發展趨勢，下列何者正確？', '["「綜合性」保險發展、「普及式」保險範疇、老年給付年金化等", "「限定式」的保險範疇、「單一化」保險發展、提高社會企業對社會保險之財務責任", "「單一化」保險發展、「普及式」保險範疇、老年給付年金化", "「限定式」的保險範疇、老年給付年金化、提高社會企業對社會保險之財務責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
