  ('social-worker-moex-02792', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為避免人口老化與社會結構改變引發老人所得安全之危機，世界銀行（World Bank）於2005年提出多柱 （pillars）式的年金體系保障模式，下列敘述何者錯誤？', '["第零柱保障：係指非繳納性的社會救助制度，其目的在於提供貧窮老人的最低生活保障", "第一柱保障：係指強制性的社會保險制度，藉由世代間所得移轉作用提供老年退休者最低生活水準的 終身保障", "第二柱保障：係指倫理性的家庭供養制度，對於無工作的家庭成員提供晚年生活照顧", "第三柱保障：係指自願性的個人商業保險儲蓄制度，不論職業年金或個人年金，均以事前提存準備方 式，用以提供長期保障"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02793', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依志願服務法，下列敘述何者正確？', '["中央主管機關應至少每6年舉辦志願服務調查研究", "各目的事業主管機關得視業務需要，將汰舊之器材及車輛無償撥交志願服務運用單位使用", "志工進入收費之公立風景區或未編定座位之康樂場所，憑志願服務榮譽卡得以免費", "志工依志願服務運用單位之指示進行志願服務時，因故意或過失不法侵害他人權利者，志工應負損害 賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02794', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關社會保險與社會救助制度的論述比較，何者正確？', '["兩者所提供的給付水準有所差異", "兩者請領時都需要經過資產調查", "社會保險的福利再分配程度比社會救助高", "兩者都具有脫貧的功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02795', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依身心障礙者權益保障法，為促進身心障礙者之社會參與，下列敘述何者錯誤？', '["縣（市）主管機關辦理復康巴士服務，不得有設籍之限制", "身心障礙者進入收費之公營風景區、康樂場所應予免費；其為民營或公設民營者，應予半價優待", "身心障礙者搭乘國內大眾運輸工具應予半價優待", "各級政府及其附屬機關、學校所建置的網站應通過第一優先等級以上之無障礙檢測"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02796', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一種社會福利財源的財富重分配效果最為顯著？', '["所得稅", "薪資稅", "使用者付費", "營業稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02797', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依社會工作師法，關於社會工作師執業及社會工作師事務所，下列敘述何者正確？', '["社會工作師執業時應撰製社會工作紀錄，其保存年限不得少於5年", "社會工作師應接受繼續教育，並每5年提出證明文件，以辦理執照更新", "社會工作師事務所之設立，其申請人應具備5年以上之社會工作師執業證明", "社會工作師事務所因故無法繼續開業且無承接者，其服務紀錄應交由主管機關保存5年後銷毀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02798', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '國民年金法對於保險給付之規定，下列敘述何者錯誤？', '["老年、身心障礙、遺屬等三項年金給付標準均採計保險年資", "生育、喪葬等兩項給付為一次給付制；前者給付1個月月投保金額，後者給付5個月月投保金額", "被保險人、受益人或其他利害關係人，故意造成保險事故者，保險人不予任何保險給付", "因戰爭變亂，致發生保險事故者，不予保險給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02799', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '女性主義是當代主要的社會福利意識形態之一，下列何者是女性主義對社會福利的態度？', '["各女性主義流派均認同福利國家可以達到修正以男性中心價值的福利效果", "基於追求兩性的平等，各女性主義流派認為社會政策制度要一體適用於男人與女人，不可有不同的政策", "不同的女性主義流派對福利國家的看法有高度的共識", "女性主義思想接受福利國家，認為在福利國家所提供的服務中，可能有助於改善女性的生活與地位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02800', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '當家庭功能完全喪失，兒童處於危機而無法繼續生長於原生家庭的情況下，國家將兒童安排到其他生活 環境，由他人執行父母的親職角色，此種方式係屬那一種類型的兒童福利服務？', '["支持性福利服務", "補充性福利服務", "替代性福利服務", "保護性福利服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02801', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列何者並非來自性別工作平等法有關受僱者「育嬰留職停薪」的相關規定？', '["受僱者必須於任職滿1年後，方可申請育嬰留職停薪", "受僱於30人以上雇主之受僱者，得申請育嬰留職停薪", "受僱者申請育嬰留職停薪期間，得繼續參加原有之社會保險；原由受僱者負擔之保險費，得遞延3年 繳納", "同時撫育2名子女以上之受僱者，申請育嬰留職停薪期間，最長以最幼子女受撫育2年為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02802', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', 'Esping-Anderson (1990) 對於福利體制（welfare regime）的研究，下列何者錯誤？', '["主張就業、工資、總體經濟等，都是福利國家整體的成分之一", "主張福利國家的發展因素源自階級和政治結盟的結構，而非源自體制制度化的歷史傳承", "採用去商品化、階層化兩項指標作為福利體制的分類依據", "提出福利國家三種型態：自由主義、保守組合主義、社會民主模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02803', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '馬克斯主義用一系列的理論假設來解釋福利國家的發展，下列敘述何者錯誤？', '["視福利國家既非善意、亦非惡意的制度，而是資本主義的一種形式", "主張一個社會主義國家的所得分配原則，應根據公民的能力來分配", "主張福利國家既是對勞工階級的讓步，也是對資產階級的保護和支持", "強調福利對資本主義的貢獻，卻忽略福利可能對私有利潤的抑制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02804', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依身心障礙者權益保障法，未提供對號座之大眾運輸工具應設置博愛座，其比率不得低於總座位數的百 分之多少？', '["五", "十", "十五", "二十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02805', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年福利與權益保障法，對於兒童課後照顧服務（中心）的規定，下列何者錯誤？', '["屬於縣（市）政府應委託或自行辦理之整合性服務之一", "其接送車應列入政府輔導管理", "其申請、設立、管理辦法由中央社政主管機關定之", "有性騷擾行為經有罪判決確定者，不得擔任兒童及少年福利機構之工作人員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02806', 'social-worker', 'social-worker-moex-103-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '關於社會福利資源供給的形式，下列敘述何者錯誤？', '["現金給付強調社會控制的原則，實物給付強調選擇自由的原則", "社會福利資源供給的形式，直接反映政策價值", "儲蓄或教育脫貧方案是以選擇自由的形式，加上社會控制的附帶條件", "抵用券的形式可平衡社會控制與消費者選擇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "944ac06427af", "answer_pdf_sha1": "e152c78dc639", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02807', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生命歷程觀點係常被用來探討人類行為與社會環境課題的基本觀點之一，有關生命歷程觀點，下列敘述 何者最為適切？', '["生命歷程觀點就是探討人類各個行為發展階段特性的理論觀點", "生命歷程觀點注重人一生常態規律性的發展歷程", "生命歷程觀點是一種解析人類行為之跨科際的人文社會理論架構", "生命歷程觀點係著重人生歷程的關鍵任務和發展課題的理論架構"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02808', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多使用社會工作服務的人，係因為遭遇到了有壓力的生活事件而前來求助。有關生活壓力的敘述中， 下列何者不恰當？', '["針對壓力的主觀經驗所引發特定的適應，稱為因應（coping）", "壓力，係指人與環境間所存在的負面關係", "當生活壓力和處在危險狀態中的感覺相關時，它會引發焦慮、無助、低自尊等等情緒感受", "生活壓力在本質上與人們的知覺密切相關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "77e308cebf0c", "answer_pdf_sha1": "9a608102a238", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
